parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"complianceStatus": {
			"type": "string",
			"description": "Overall compliance status"
		},
		"riskLevel": {
			"type": "string",
			"description": "Risk level assessment"
		},
		"regulationViolations": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "List of regulation violations"
		},
		"approvalRequired": {
			"type": "boolean",
			"description": "Whether approval is required"
		},
		"findings": {
			"type": "string",
			"description": "Detailed findings from the compliance audit"
		},
		"recommendations": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "List of recommendations"
		},
		"auditTrail": {
			"type": "object",
			"description": "Audit trail information"
		}
	}
}
